package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testGetHeader() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT.withHeader("Header1", "Header2");

        // When
        Method method = CSVFormat.class.getDeclaredMethod("getHeader");
        method.setAccessible(true);
        String[] result = (String[]) method.invoke(csvFormat);

        // Then
        assertArrayEquals(new String[]{"Header1", "Header2"}, result);
    }
}
